UPDATE packages SET is_active = false
WHERE organization_id = (SELECT id FROM organizations WHERE slug='lasema')
  AND code IN ('PKG_LASEMA_COUPLE','PKG_MASSAGE_COUPLE','PKG_SAUNA','PKG_JJIMJILBANG');

INSERT INTO packages (organization_id, code, name, description, max_stay_hours, default_pax, is_couple, includes_massage, bundles_private_room, requires_vip_room)
SELECT id, 'PKG_VIP_MASSAGE', 'VIP Massage Package', 'VIP room + 1 hr jacuzzi + 1 hr massage + 1 hr wet sauna, 3 hr stay', 3, 1, false, true, false, true FROM organizations WHERE slug='lasema';

INSERT INTO packages (organization_id, code, name, description, max_stay_hours, default_pax, is_couple, includes_massage, bundles_private_room, requires_vip_room)
SELECT id, 'PKG_VIP_FULL', 'VIP Full Package', 'VIP room + jacuzzi + massage + wet and dry sauna + full facility, 12 hr stay', 12, 1, false, true, false, true FROM organizations WHERE slug='lasema';

UPDATE rooms SET is_active = false WHERE organization_id = (SELECT id FROM organizations WHERE slug='lasema');

INSERT INTO rooms (organization_id, room_number, floor, room_type, row_segmented, is_active, vip_tier) SELECT id, 'Room 1', 1, 'COMMON', false, true, NULL FROM organizations WHERE slug='lasema';
