INSERT INTO beds (room_id, bed_label, is_active) SELECT r.id, b.label, true FROM rooms r CROSS JOIN (VALUES ('1'),('2'),('3'),('4')) AS b(label) WHERE r.organization_id = (SELECT id FROM organizations WHERE slug='lasema') AND r.room_number = 'Room 1';
